mapper.select:
SELECT id, unit_id, user_id, attendance_date, check_in_time, check_out_time,
       check_in_address, check_out_address, valid_flag, create_time
FROM attendance_record
WHERE user_id = #{userId}
  AND attendance_date = #{attendanceDate}

mapper.update:
UPDATE attendance_record
SET valid_flag = #{validFlag}
WHERE id = #{id}

mapper.select:
SELECT COUNT(DISTINCT a.user_id)
FROM attendance_record a
WHERE 1 = 1

    AND a.attendance_date >= #{startDate}


    AND a.attendance_date <= #{endDate}


    AND a.valid_flag = #{validFlag}


    AND a.unit_id = #{unitId}

SELECT a.id, a.unit_id, a.user_id, u.username, u.real_name, su.unit_name, a.attendance_date, a.check_in_time, a.check_out_time, a.check_in_address, a.check_out_address, a.valid_flag, a.create_time FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE
AND ( u.username LIKE CONCAT('%', #{request.keywords}, '%') OR u.real_name LIKE CONCAT('%', #{request.keywords}, '%') )
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND a.unit_id = #{request.unitId}
ORDER BY a.attendance_date DESC, a.check_in_time DESC NULLS LAST, a.id DESC
